   200	/*
   201	** Parse times of the form HH:MM or HH:MM:SS or HH:MM:SS.FFFF.
   202	** The HH, MM, and SS must each be exactly 2 digits.  The
   203	** fractional seconds FFFF can be one or more digits.
   204	**
   205	** Return 1 if there is a parsing error and 0 on success.
   206	*/
   207	static int parseHhMmSs(const char *zDate, DateTime *p){
   208	  int h, m, s;
   209	  double ms = 0.0;
   210	  if( getDigits(zDate, "20c:20e", &h, &m)!=2 ){
   211	    return 1;
   212	  }
   213	  zDate += 5;
   214	  if( *zDate==':' ){
   215	    zDate++;
   216	    if( getDigits(zDate, "20e", &s)!=1 ){
   217	      return 1;
   218	    }
   219	    zDate += 2;
   220	    if( *zDate=='.' && sqlite3Isdigit(zDate[1]) ){
   221	      double rScale = 1.0;
   222	      zDate++;
   223	      while( sqlite3Isdigit(*zDate) ){
   224	        ms = ms*10.0 + *zDate - '0';
   225	        rScale *= 10.0;
   226	        zDate++;
   227	      }
   228	      ms /= rScale;
   229	      /* Truncate to avoid problems with sub-milliseconds
   230	      ** rounding. https://sqlite.org/forum/forumpost/766a2c9231 */
   231	      if( ms>0.999 ) ms = 0.999;
   232	    }
   233	  }else{
   234	    s = 0;
   235	  }
   236	  p->validJD = 0;
   237	  p->rawS = 0;
   238	  p->validHMS = 1;
   239	  p->h = h;
   240	  p->m = m;
   241	  p->s = s + ms;
   242	  if( parseTimezone(zDate, p) ) return 1;
   243	  return 0;
   244	}
