   300	/*
   301	** Given the YYYY-MM-DD information current in p, determine if there
   302	** is day-of-month overflow and set nFloor to the number of days that
   303	** would need to be subtracted from the date in order to bring the
   304	** date back to the end of the month.
   305	*/
   306	static void computeFloor(DateTime *p){
   307	  assert( p->validYMD || p->isError );
   308	  assert( p->D>=0 && p->D<=31 );
   309	  assert( p->M>=0 && p->M<=12 );
   310	  if( p->D<=28 ){
   311	    p->nFloor = 0;
   312	  }else if( (1<<p->M) & 0x15aa ){
   313	    p->nFloor = 0;
   314	  }else if( p->M!=2 ){
   315	    p->nFloor = (p->D==31);
   316	  }else if( p->Y%4!=0 || (p->Y%100==0 && p->Y%400!=0) ){
   317	    p->nFloor = p->D - 28;
   318	  }else{
   319	    p->nFloor = p->D - 29;
   320	  }
   321	}
