   404	/*
   405	** Attempt to parse the given string into a julian day number.  Return
   406	** the number of errors.
   407	**
   408	** The following are acceptable forms for the input string:
   409	**
   410	**      YYYY-MM-DD HH:MM:SS.FFF  +/-HH:MM
   411	**      DDDD.DD 
   412	**      now
   413	**
   414	** In the first form, the +/-HH:MM is always optional.  The fractional
   415	** seconds extension (the ".FFF") is optional.  The seconds portion
   416	** (":SS.FFF") is option.  The year and date can be omitted as long
   417	** as there is a time string.  The time string can be omitted as long
   418	** as there is a year and date.
   419	*/
   420	static int parseDateOrTime(
   421	  sqlite3_context *context, 
   422	  const char *zDate, 
   423	  DateTime *p
   424	){
   425	  double r;
   426	  if( parseYyyyMmDd(zDate,p)==0 ){
   427	    return 0;
   428	  }else if( parseHhMmSs(zDate, p)==0 ){
   429	    return 0;
   430	  }else if( sqlite3StrICmp(zDate,"now")==0 && sqlite3NotPureFunc(context) ){
   431	    return setDateTimeToCurrent(context, p);
   432	  }else if( sqlite3AtoF(zDate, &r, sqlite3Strlen30(zDate), SQLITE_UTF8)>0 ){
   433	    setRawDateNumber(p, r);
   434	    return 0;
   435	  }else if( (sqlite3StrICmp(zDate,"subsec")==0
   436	             || sqlite3StrICmp(zDate,"subsecond")==0)
   437	           && sqlite3NotPureFunc(context) ){
   438	    p->useSubsec = 1;
   439	    return setDateTimeToCurrent(context, p);
   440	  }
   441	  return 1;
   442	}
