   444	/* The julian day number for 9999-12-31 23:59:59.999 is 5373484.4999999.
   445	** Multiplying this by 86400000 gives 464269060799999 as the maximum value
   446	** for DateTime.iJD.
   447	**
   448	** But some older compilers (ex: gcc 4.2.1 on older Macs) cannot deal with 
   449	** such a large integer literal, so we have to encode it.
   450	*/
   451	#define INT_464269060799999  ((((i64)0x1a640)<<32)|0x1072fdff)
   452	
   453	/*
   454	** Return TRUE if the given julian day number is within range.
   455	**
   456	** The input is the JulianDay times 86400000.
   457	*/
   458	static int validJulianDay(sqlite3_int64 iJD){
   459	  return iJD>=0 && iJD<=INT_464269060799999;
   460	}
   461	
   462	/*
   463	** Compute the Year, Month, and Day from the julian day number.
   464	*/
   465	static void computeYMD(DateTime *p){
   466	  int Z, alpha, A, B, C, D, E, X1;
   467	  if( p->validYMD ) return;
   468	  if( !p->validJD ){
   469	    p->Y = 2000;
   470	    p->M = 1;
   471	    p->D = 1;
   472	  }else if( !validJulianDay(p->iJD) ){
   473	    datetimeError(p);
   474	    return;
   475	  }else{
   476	    Z = (int)((p->iJD + 43200000)/86400000);
   477	    alpha = (int)((Z + 32044.75)/36524.25) - 52;
   478	    A = Z + 1 + alpha - ((alpha+100)/4) + 25;
   479	    B = A + 1524;
   480	    C = (int)((B - 122.1)/365.25);
   481	    D = (36525*(C&32767))/100;
   482	    E = (int)((B-D)/30.6001);
   483	    X1 = (int)(30.6001*E);
   484	    p->D = B - D - X1;
   485	    p->M = E<14 ? E-1 : E-13;
   486	    p->Y = p->M>2 ? C - 4716 : C - 4715;
   487	  }
   488	  p->validYMD = 1;
   489	}
   490	
   491	/*
   492	** Compute the Hour, Minute, and Seconds from the julian day number.
   493	*/
   494	static void computeHMS(DateTime *p){
   495	  int day_ms, day_min; /* milliseconds, minutes into the day */
   496	  if( p->validHMS ) return;
   497	  computeJD(p);
   498	  day_ms = (int)((p->iJD + 43200000) % 86400000);
   499	  p->s = (day_ms % 60000)/1000.0;
   500	  day_min = day_ms/60000;
   501	  p->m = day_min % 60;
   502	  p->h = day_min / 60;
   503	  p->rawS = 0;
   504	  p->validHMS = 1;
   505	}
   506	
   507	/*
   508	** Compute both YMD and HMS
   509	*/
   510	static void computeYMD_HMS(DateTime *p){
   511	  computeYMD(p);
   512	  computeHMS(p);
   513	}
