   515	/*
   516	** Clear the YMD and HMS and the TZ
   517	*/
   518	static void clearYMD_HMS_TZ(DateTime *p){
   519	  p->validYMD = 0;
   520	  p->validHMS = 0;
   521	  p->tz = 0;
